import{_ as a,o as s,c as t,ag as n}from"./chunks/framework.eQLvDOR_.js";const u=JSON.parse('{"title":"Run multiple agents at once with /fleet in Copilot CLI","description":"","frontmatter":{"title":"Run multiple agents at once with /fleet in Copilot CLI","source":"https://github.blog/ai-and-ml/github-copilot/run-multiple-agents-at-once-with-fleet-in-copilot-cli/?utm_source=twitter-cli-fleet-agents-blog-cta&utm_medium=social&utm_campaign=dev-pod-copilot-cli-2026","clipped_at":"2026-04-18","category":"AI_IDE_And_CLI","tags":["copilot-cli","fleet-mode","multi-agent"],"status":"distilled","compiled":true},"headers":[],"relativePath":"library/AI_IDE_And_CLI/AI_IDE_And_CLI - Run multiple agents at once with _fleet in Copilot CLI.md","filePath":"library/AI_IDE_And_CLI/AI_IDE_And_CLI - Run multiple agents at once with _fleet in Copilot CLI.md","lastUpdated":null}'),i={name:"library/AI_IDE_And_CLI/AI_IDE_And_CLI - Run multiple agents at once with _fleet in Copilot CLI.md"};function o(l,e,p,r,c,d){return s(),t("div",null,[...e[0]||(e[0]=[n(`<p>What if <a href="https://github.com/features/copilot/cli?utm_source=blog-cli-fleet-agents-cta&amp;utm_medium=blog&amp;utm_campaign=dev-pod-copilot-cli-2026" target="_blank" rel="noreferrer">GitHub Copilot CLI</a> could work on five files at the same time instead of one? That’s where <code>/fleet</code> comes in.</p><p><code>/fleet</code> is a slash command in Copilot CLI that enables Copilot to simultaneously work with multiple subagents in parallel. Instead of working through tasks sequentially, Copilot now has a behind the scenes orchestrator that plans and breaks your objective into independent work items and dispatches multiple agents to execute them simultaneously. On different files, in different parts of your codebase, all at once.</p><p>Want to learn more about how <code>/fleet</code> works, and more importantly, how to use it most effectively? Let’s jump in.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>When you run <code>/fleet</code> with a prompt, the behind-the-scenes orchestrator:</p><ol><li>Decomposes your task into discrete work items with dependencies.</li><li>Identifies which items can run in parallel versus which must wait.</li><li>Dispatches independent items as background sub-agents simultaneously.</li><li>Polls for completion, then dispatches the next wave.</li><li>Verifies outputs and synthesizes any final artifacts.</li></ol><p>Each sub-agent gets its own context window but shares the same filesystem. They can’t talk to each other directly; only the orchestrator coordinates.</p><p>Think of it as a project lead who assigns work to a team, checks in on progress, and assembles the final deliverable.</p><h2 id="getting-started" tabindex="-1">Getting started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting started&quot;">​</a></h2><p>Start fleet mode by sending <code>/fleet &lt;YOUR OBJECTIVE PROMPT&gt;</code>. For example:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/fleet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Refactor</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> the</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> module,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tests,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> and</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fix</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> the</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> related</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> in</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> the</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> folder</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs/auth/</span></span></code></pre></div><p>That’s it. The orchestrator takes your objective, figures out what can be parallelized, and starts dispatching.</p><p>You can also run it non-interactively in your terminal:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>copilot -p &quot;/fleet &lt;YOUR TASK&gt;&quot; --no-ask-user</span></span></code></pre></div><p>The <code>--no-ask-user</code> flag is required for non-interactive mode, since there’s no way to respond to prompts. Now let’s look at what makes a good prompt.</p><h2 id="write-prompts-that-parallelize-well" tabindex="-1">Write prompts that parallelize well <a class="header-anchor" href="#write-prompts-that-parallelize-well" aria-label="Permalink to &quot;Write prompts that parallelize well&quot;">​</a></h2><p>The quality of your <code>/fleet</code> prompt determines how effectively work gets distributed. The key is giving the orchestrator enough structure to cleanly break down your task.</p><p>A good way to do that is being specific about deliverables. Map every work item to a concrete artifact like a file, a test suite, or a section of documentation. Vague prompts lead to sequential execution because the orchestrator can’t identify independent pieces.</p><p>For example, instead of: <code>/fleet Build the documentation</code>, you could try:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/fleet Create docs for the API module: </span></span>
<span class="line"><span></span></span>
<span class="line"><span>- docs/authentication.md covering token flow and examples </span></span>
<span class="line"><span></span></span>
<span class="line"><span>- docs/endpoints.md with request/response schemas for all REST endpoints </span></span>
<span class="line"><span></span></span>
<span class="line"><span>- docs/errors.md with error codes and troubleshooting steps </span></span>
<span class="line"><span></span></span>
<span class="line"><span>- docs/index.md linking to all three pages (depends on the others finishing first)</span></span></code></pre></div><p>The second prompt gives the orchestrator four distinct deliverables, three of which can run in parallel, and one that depends on them.</p><h2 id="set-explicit-boundaries" tabindex="-1">Set explicit boundaries <a class="header-anchor" href="#set-explicit-boundaries" aria-label="Permalink to &quot;Set explicit boundaries&quot;">​</a></h2><p>Sub-agents work best when they know exactly where their scope starts and ends. When writing your prompt include:</p><ul><li>File or module boundaries: Which directories or files each track owns</li><li>Constraints: What not to touch (e.g., no test changes, no dependency upgrades)</li><li>Validation criteria: Lint, type checks, tests that must pass</li></ul><p>Here’s a prompt that showcases these boundaries:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/fleet Implement feature flags in three tracks: </span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. API layer: add flag evaluation to src/api/middleware/ and include unit tests that look for successful flag evaluation and tests API endpoints  </span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. UI: wire toggle components in src/components/flags/ and introduce no new dependencies </span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. Config: add flag definitions to config/features.yaml  and validate against schema </span></span>
<span class="line"><span></span></span>
<span class="line"><span>Run independent tracks in parallel. No changes outside assigned directories.</span></span></code></pre></div><h2 id="declare-dependencies-when-they-exist" tabindex="-1">Declare dependencies when they exist <a class="header-anchor" href="#declare-dependencies-when-they-exist" aria-label="Permalink to &quot;Declare dependencies when they exist&quot;">​</a></h2><p>If one piece of work depends on another, say so. The orchestrator will serialize those items and parallelize the rest. For example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/fleet Migrate the database layer: </span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. Write new schema in migrations/005_users.sql </span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. Update the ORM models in src/models/user.ts (depends on 1) </span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. Update API handlers in src/api/users.ts (depends on 2) </span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. Write integration tests in tests/users.test.ts (depends on 2) </span></span>
<span class="line"><span></span></span>
<span class="line"><span> Items 3 and 4 can run in parallel after item 2 completes.</span></span></code></pre></div><h2 id="use-custom-agents-for-different-jobs" tabindex="-1">Use custom agents for different jobs <a class="header-anchor" href="#use-custom-agents-for-different-jobs" aria-label="Permalink to &quot;Use custom agents for different jobs&quot;">​</a></h2><p>You can define specialized agents in <code>.github/agents/</code> and reference them in your <code>/fleet</code> prompt. Each agent can specify its own model, tools, and instructions. Be aware that if you don’t specify which model to use, agents will use the current default model.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># .github/agents/technical-writer.md </span></span>
<span class="line"><span></span></span>
<span class="line"><span>--- </span></span>
<span class="line"><span></span></span>
<span class="line"><span>name: technical-writer </span></span>
<span class="line"><span></span></span>
<span class="line"><span>description: Documentation specialist </span></span>
<span class="line"><span></span></span>
<span class="line"><span>model: claude-sonnet-4 </span></span>
<span class="line"><span></span></span>
<span class="line"><span>tools: [&quot;bash&quot;, &quot;create&quot;, &quot;edit&quot;, &quot;view&quot;] </span></span>
<span class="line"><span></span></span>
<span class="line"><span>--- </span></span>
<span class="line"><span></span></span>
<span class="line"><span>You write clear, concise technical documentation. Follow the project style guide in /docs/styleguide.md.</span></span></code></pre></div><p>Then reference the custom agent in your prompt:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/fleet Use @technical-writer.md as the agent for all docs tasks and the default agent for code changes.</span></span></code></pre></div><p>This is useful when different tracks need different strengths such as using a heavier model for complex logic and a lighter one for boilerplate documentation.</p><h2 id="how-to-verify-subagents-are-deploying" tabindex="-1">How to verify subagents are deploying <a class="header-anchor" href="#how-to-verify-subagents-are-deploying" aria-label="Permalink to &quot;How to verify subagents are deploying&quot;">​</a></h2><p>Watch how the orchestrator deploys subagents, it’s the fastest way to learn how to write prompts that parallelize well.</p><p>Use this quick checklist:</p><ul><li>Decomposition appears: Before it starts working, review the plan Copilot shares with you to see if it breaks work into multiple tracks, instead of one long linear plan.</li><li>Background task UI confirms activity: Once it begins working, run <code>/tasks</code> to open the tasks dialog and inspect running background tasks.</li><li>Parallel progress appears: Updates reference separate tracks moving at the same time.</li></ul><p>If the fleet doesn’t seem to be parallelizing, try stopping Copilot’s work and asking for an explicit decomposition:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Decompose this into independent tracks first, then execute tracks in parallel. Report each track separately with status and blockers.</span></span></code></pre></div><h2 id="avoiding-common-pitfalls" tabindex="-1">Avoiding common pitfalls <a class="header-anchor" href="#avoiding-common-pitfalls" aria-label="Permalink to &quot;Avoiding common pitfalls&quot;">​</a></h2><p>Fleet is powerful, but a few gotchas are worth knowing upfront.</p><h3 id="partition-your-files" tabindex="-1">Partition your files <a class="header-anchor" href="#partition-your-files" aria-label="Permalink to &quot;Partition your files&quot;">​</a></h3><p>Sub-agents share a filesystem with no file locking. If two agents write to the same file, the last one to finish wins—silently. No error, no merge, just an overwrite.</p><p>The fix is to assign each agent distinct files in your prompt. If multiple agents need to contribute to a single file, consider having each write to a temporary path and let the orchestrator merge them at the end. Or set an explicit order for the agents to follow.</p><h3 id="keep-prompts-self-contained" tabindex="-1">Keep prompts self-contained <a class="header-anchor" href="#keep-prompts-self-contained" aria-label="Permalink to &quot;Keep prompts self-contained&quot;">​</a></h3><p>Sub-agents can’t see the orchestrator’s conversation history. When the orchestrator dispatches a sub-agent, it passes along a prompt, but that prompt needs to include everything the sub-agent needs. If you’ve already gathered useful context earlier in the session, make sure your <code>/fleet</code> prompt includes it (or references files the sub-agents can read).</p><h3 id="steering-a-fleet-in-progress" tabindex="-1">Steering a fleet in progress <a class="header-anchor" href="#steering-a-fleet-in-progress" aria-label="Permalink to &quot;Steering a fleet in progress&quot;">​</a></h3><p>After dispatching, you can send follow-up prompts to guide the orchestrator:</p><ul><li><code>Prioritize failing tests first, then complete remaining tasks.</code></li><li><code>List active sub-agents and what each is currently doing.</code></li><li><code>Mark done only when lint, type check, and all tests pass.</code></li></ul><h2 id="when-to-use-fleet-and-when-not-to" tabindex="-1">When to use /fleet (and when not to) <a class="header-anchor" href="#when-to-use-fleet-and-when-not-to" aria-label="Permalink to &quot;When to use /fleet (and when not to)&quot;">​</a></h2><p><code>/fleet</code> shines when your task has natural parallelism—multiple files, independent modules, or separable concerns. It’s particularly effective for:</p><ul><li>Refactoring across multiple files simultaneously.</li><li>Generating documentation for several components at once.</li><li>Implementing a feature that spans API, UI, and tests.</li><li>Running independent code modifications that don’t share state.</li></ul><p>For strictly linear, single-file work, regular Copilot CLI prompts are simpler and just as fast. Fleet adds coordination overhead, so it pays off when there’s real work to distribute.</p><p><code>/fleet</code> is most useful when you treat it like a team, not a magic trick. Start small. Pick a task with clear outputs, clean file boundaries, and obvious parallelism. See how the orchestrator decomposes the work, where it helps, and where it gets in the way. As you get more comfortable, push it further with larger refactors, multi‑track features, or docs and tests in parallel. The fastest way to learn when <code>/fleet</code> pays off is to try it on real work and adjust your prompts based on what you see.</p>`,56)])])}const g=a(i,[["render",o]]);export{u as __pageData,g as default};
